import React, { useEffect, useState, useMemo } from 'react';
import { supabase } from '../services/supabaseClient';
import { PiggyBank, AlertCircle, ArrowUpCircle, Target, CreditCard, Calendar, TrendingUp } from 'lucide-react';
import '../styles/Orcamento.css';

const Orcamento = () => {
  const [loading, setLoading] = useState(true);
  const [dados, setDados] = useState({
    metaReceita: 0,
    receitaReal: 0,
    metaGasto: 0,
    gastoReal: 0,
    gastoCartao: 0,
    gastoVariavel: 0,
    categoriasDespesa: [],
    objetivosPessoais: []
  });

  useEffect(() => {
    buscarDadosCompletos();
  }, []);

  const formatMoney = (v) => {
    const valor = Number(v) || 0;
    return valor.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
  };

  async function buscarDadosCompletos() {
    setLoading(true);
    try {
      const agora = new Date();
      const ano = agora.getFullYear();
      const mes = agora.getMonth() + 1;
      const primeiroDia = `${ano}-${String(mes).padStart(2, '0')}-01`;
      const ultimoDia = new Date(ano, mes, 0).toISOString().split('T')[0];

      const [
        { data: metasData },
        { data: proventos },
        { data: comprasVariaveis },
        { data: parcelasMes },
        { data: cats }
      ] = await Promise.all([
        supabase.from('metas').select('*').eq('mes_referencia', mes).eq('ano_referencia', ano),
        supabase.from('proventos').select('valor').gte('data_recebimento', primeiroDia).lte('data_recebimento', ultimoDia),
        supabase.from('compras').select('valor_total, categoria_id').gte('data_compra', primeiroDia).lte('data_compra', ultimoDia),
        supabase.from('parcelas').select('valor_parcela, compras!inner(categoria_id)').gte('data_vencimento', primeiroDia).lte('data_vencimento', ultimoDia),
        supabase.from('categorias').select('*').order('nome', { ascending: true })
      ]);

      // --- PROCESSAMENTO DE GASTOS POR CATEGORIA ---
      const gastosPorCat = {};
      comprasVariaveis?.forEach(c => {
        gastosPorCat[c.categoria_id] = (gastosPorCat[c.categoria_id] || 0) + Number(c.valor_total);
      });
      parcelasMes?.forEach(p => {
        const catId = p.compras?.categoria_id;
        if (catId) {
          gastosPorCat[catId] = (gastosPorCat[catId] || 0) + Number(p.valor_parcela);
        }
      });

      // Consolidação de todas as categorias com suas metas e gastos reais
      const todasCategorias = (cats || []).map(cat => {
        const metaEncontrada = metasData?.find(m => m.categoria_id === cat.id);
        return {
          ...cat,
          gastoReal: Number(gastosPorCat[cat.id] || 0),
          metaValor: metaEncontrada ? Number(metaEncontrada.valor_objetivo) : 0,
          tipoMeta: metaEncontrada?.tipo_meta || 'despesa'
        };
      });

      // --- SEPARAÇÃO DE GRUPOS ---
      // 1. Categorias de Despesa Comum
      const categoriasDespesa = todasCategorias.filter(c => c.tipo === 'despesa' && c.tipoMeta !== 'pessoal');
      
      // 2. Objetivos Pessoais (Categorias que possuem meta do tipo 'pessoal')
      const objetivosPessoais = todasCategorias.filter(c => c.tipoMeta === 'pessoal');

      // --- TOTAIS GLOBAIS ---
      const totalReceitaReal = proventos?.reduce((acc, cur) => acc + Number(cur.valor), 0) || 0;
      const totalVariavel = comprasVariaveis?.reduce((acc, cur) => acc + Number(cur.valor_total), 0) || 0;
      const totalCartao = parcelasMes?.reduce((acc, cur) => acc + Number(cur.valor_parcela), 0) || 0;
      const totalGastoReal = totalVariavel + totalCartao;

      const totalMetaGasto = metasData?.filter(m => m.tipo_meta === 'despesa').reduce((a, b) => a + Number(b.valor_objetivo), 0) || 0;
      const totalMetaReceita = metasData?.filter(m => m.tipo_meta === 'provento').reduce((a, b) => a + Number(b.valor_objetivo), 0) || 0;

      setDados({
        metaReceita: totalMetaReceita,
        receitaReal: totalReceitaReal,
        metaGasto: totalMetaGasto > 0 ? totalMetaGasto : totalReceitaReal,
        gastoReal: totalGastoReal,
        gastoCartao: totalCartao,
        gastoVariavel: totalVariavel,
        categoriasDespesa,
        objetivosPessoais
      });

    } catch (err) {
      console.error("Erro geral no orçamento:", err);
    } finally {
      setLoading(false);
    }
  }

  const porcGasto = useMemo(() => 
    dados.metaGasto > 0 ? (dados.gastoReal / dados.metaGasto) * 100 : 0
  , [dados.gastoReal, dados.metaGasto]);

  const mesAtualNome = new Intl.DateTimeFormat('pt-BR', { month: 'long' }).format(new Date());

  if (loading) return <div className="loading-state">Carregando planejamento de {mesAtualNome}...</div>;

  return (
    <div className="orcamento-container fade-in">
      <header className="orcamento-header">
        <div>
           <h2>Gestão Mensal</h2>
           <p className="mes-referencia">
             <Calendar size={14} style={{verticalAlign: 'middle', marginRight: '5px'}} />
             Mês de: <strong>{mesAtualNome.toUpperCase()}</strong>
           </p>
        </div>
        <button className="btn-ajuste" onClick={() => window.location.href='/categoriasMetas'}>
          <Target size={18} /> Definir Metas
        </button>
      </header>

      {/* BLOCO 1: VISÃO GERAL DE GASTOS */}
      <section className="meta-global-card">
        <div className="meta-info">
          <div className="meta-text">
            <span className="label">Limite de Gastos do Mês</span>
            <h3>{formatMoney(dados.gastoReal)} <small>/ {formatMoney(dados.metaGasto)}</small></h3>
          </div>
          <PiggyBank size={40} className="icon-main" style={{color: '#ef4444'}} />
        </div>
        <div className="progress-bar-container">
          <div 
            className={`progress-bar-fill ${porcGasto > 100 ? 'over-limit' : ''}`} 
            style={{ width: `${Math.min(porcGasto, 100)}%` }} 
          />
        </div>
        <div className="meta-footer">
          <span className="progress-label">{porcGasto.toFixed(1)}% utilizado</span>
          <span className="remaining-label">
            {dados.gastoReal > dados.metaGasto 
              ? `Excedido: ${formatMoney(dados.gastoReal - dados.metaGasto)}`
              : `Disponível: ${formatMoney(dados.metaGasto - dados.gastoReal)}`
            }
          </span>
        </div>
      </section>

      {/* BLOCO 2: RECEITAS E SAÍDAS */}
      <div className="two-columns-grid">
        <section className="orc-section">
          <h3 className="section-title"><ArrowUpCircle size={18} color="#10b981" /> Receita (Real vs Meta)</h3>
          <div className="summary-box proventos-bg">
            <p className="value">{formatMoney(dados.receitaReal)}</p>
            <span className="label">Meta: {formatMoney(dados.metaReceita)}</span>
          </div>
        </section>

        <section className="orc-section">
          <h3 className="section-title"><CreditCard size={18} color="#ef4444" /> Distribuição de Saídas</h3>
          <div className="summary-box despesas-bg">
            <div style={{display: 'flex', justifyContent: 'space-between'}}>
                <div><span className="label">Fatura:</span> <strong>{formatMoney(dados.gastoCartao)}</strong></div>
                <div><span className="label">À Vista:</span> <strong>{formatMoney(dados.gastoVariavel)}</strong></div>
            </div>
          </div>
        </section>
      </div>

      {/* BLOCO 3: OBJETIVOS PESSOAIS (Agora com progresso real) */}
      {dados.objetivosPessoais.length > 0 && (
        <section className="metas-pessoais-section" style={{marginTop: '20px'}}>
          <h3 className="section-title"><TrendingUp size={18} color="#8b5cf6" /> Objetivos Pessoais</h3>
          <div className="metas-pessoais-grid">
            {dados.objetivosPessoais.map(meta => {
              const porcPessoal = meta.metaValor > 0 ? (meta.gastoReal / meta.metaValor) * 100 : 0;
              return (
                <div key={meta.id} className="pessoal-card">
                  <div className="pessoal-header">
                    <span className="pessoal-nome">{meta.nome}</span>
                    <span className="pessoal-porc">{porcPessoal.toFixed(0)}%</span>
                  </div>
                  <div className="pessoal-valores">
                    <strong>{formatMoney(meta.gastoReal)}</strong>
                    <small>de {formatMoney(meta.metaValor)}</small>
                  </div>
                  <div className="mini-progress-bg" style={{height: '4px', marginTop: '8px'}}>
                    <div 
                      className="mini-progress-fill" 
                      style={{ 
                        width: `${Math.min(porcPessoal, 100)}%`, 
                        backgroundColor: '#8b5cf6' 
                      }} 
                    />
                  </div>
                </div>
              );
            })}
          </div>
        </section>
      )}

      {/* BLOCO 4: DETALHAMENTO POR CATEGORIA (Apenas despesas padrão) */}
      <h3 className="section-title" style={{marginTop: '30px'}}>Metas por Categoria</h3>
      <div className="orcamento-grid">
        {dados.categoriasDespesa.map((cat) => {
          const porc = cat.metaValor > 0 ? (cat.gastoReal / cat.metaValor) * 100 : 0;
          const excedeu = cat.gastoReal > cat.metaValor && cat.metaValor > 0;

          return (
            <div key={cat.id} className={`categoria-card ${excedeu ? 'card-excedido' : ''}`}>
              <div className="categoria-header">
                <div className="cat-info-main">
                  <div className="dot" style={{backgroundColor: cat.cor}}></div>
                  <span className="cat-nome">{cat.nome}</span>
                </div>
                {excedeu && <AlertCircle size={16} color="#ef4444" />}
              </div>
              <div className="cat-body">
                <div className="categoria-valores">
                  <div className="v-group">
                    <label>Real</label>
                    <span className="valor-gasto">{formatMoney(cat.gastoReal)}</span>
                  </div>
                  <div className="v-group align-right">
                    <label>Meta</label>
                    <span className="valor-meta">{formatMoney(cat.metaValor)}</span>
                  </div>
                </div>
                <div className="mini-progress-bg">
                  <div 
                    className="mini-progress-fill" 
                    style={{ 
                      width: `${Math.min(porc, 100)}%`, 
                      backgroundColor: excedeu ? '#ef4444' : cat.cor 
                    }} 
                  />
                </div>
                <span className="porc-individual">{porc.toFixed(0)}%</span>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default Orcamento;
